solution_code:
#include <iostream>

void printSquare(int n) {
    std::cout << n << "^2 = " << n * n << "\n";
}

int main() {
    int a{};
    int b{};
    std::cin >> a >> b;

    printSquare(a);
    printSquare(b);
    return 0;
}

