solution_code:
#include <iostream>

void printSummary(int x, int y) {
    std::cout << "Sum: " << x + y << "\n";
    std::cout << "Difference: " << x - y << "\n";
    std::cout << "Product: " << x * y << "\n";
}

int main() {
    int x{};
    int y{};
    std::cin >> x >> y;
    printSummary(x, y);
    return 0;
}
